import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"白云观","description":"","frontmatter":{},"headers":[],"relativePath":"religion/baiyunguan.md","filePath":"religion/baiyunguan.md","lastUpdated":null}'),o={name:"religion/baiyunguan.md"};function i(n,t,h,d,s,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="白云观" tabindex="-1">白云观 <a class="header-anchor" href="#白云观" aria-label="Permalink to &quot;白云观&quot;">​</a></h1><blockquote><p>&quot;道教全真派祖庭，丘处机祖师修炼之地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>白云观位于北京市西城区白云观街，是道教全真龙门派祖庭，也是道教全真三大祖庭之一。白云观始建于唐开元二十七年（739年），元代长春真人丘处机在此修道，并葬于此，使白云观成为全真教圣地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-16:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">10元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳时间</strong></td><td style="text-align:left;">春节庙会期间</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线/9号线军事博物馆站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区白云观街9号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>白云观始建于唐开元二十七年（739年），原名天长观，是唐玄宗为奉祀老子而建。</p><h3 id="丘处机与白云观" tabindex="-1">丘处机与白云观 <a class="header-anchor" href="#丘处机与白云观" aria-label="Permalink to &quot;丘处机与白云观&quot;">​</a></h3><p>元太祖十九年（1224年），全真教掌教丘处机赴西域朝见成吉思汗（&quot;一言止杀&quot;），返回燕京后，住于太极宫（即白云观）。</p><p>丘处机在此传教，使白云观成为全真教中心。元太祖二十二年（1227年），丘处机羽化，葬于白云观。</p><h3 id="明代重建" tabindex="-1">明代重建 <a class="header-anchor" href="#明代重建" aria-label="Permalink to &quot;明代重建&quot;">​</a></h3><p>明洪武二十七年（1394年），白云观毁于火灾。明正统八年（1443年），重建并改称&quot;白云观&quot;。</p><h3 id="清代扩建" tabindex="-1">清代扩建 <a class="header-anchor" href="#清代扩建" aria-label="Permalink to &quot;清代扩建&quot;">​</a></h3><p>清康熙年间，白云观大规模扩建，形成今日规模。康熙帝曾多次驾临白云观，题写匾额。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>白云观坐北朝南，分中、东、西三路，主要建筑在中轴线上。</p><h3 id="山门" tabindex="-1">山门 <a class="header-anchor" href="#山门" aria-label="Permalink to &quot;山门&quot;">​</a></h3><p>白云观山门为石结构，门额上书&quot;敕建白云观&quot;。山门内有&quot;窝风桥&quot;，桥下无水，是道教&quot;遇风则化&quot;之意。</p><h3 id="灵官殿" tabindex="-1">灵官殿 <a class="header-anchor" href="#灵官殿" aria-label="Permalink to &quot;灵官殿&quot;">​</a></h3><p>灵官殿是白云观的第一重大殿，供奉道教护法神王灵官。</p><h3 id="玉皇殿" tabindex="-1">玉皇殿 <a class="header-anchor" href="#玉皇殿" aria-label="Permalink to &quot;玉皇殿&quot;">​</a></h3><p>玉皇殿供奉玉皇大帝，是白云观的主要殿堂之一。</p><h3 id="老律堂" tabindex="-1">老律堂 <a class="header-anchor" href="#老律堂" aria-label="Permalink to &quot;老律堂&quot;">​</a></h3><p>老律堂是白云观的法堂，是举行法会的地方。</p><h3 id="邱祖殿" tabindex="-1">邱祖殿 <a class="header-anchor" href="#邱祖殿" aria-label="Permalink to &quot;邱祖殿&quot;">​</a></h3><p>邱祖殿是供奉丘处机祖师的殿堂，是白云观最重要的殿堂。</p><h4 id="丘处机遗蜕" tabindex="-1">丘处机遗蜕 <a class="header-anchor" href="#丘处机遗蜕" aria-label="Permalink to &quot;丘处机遗蜕&quot;">​</a></h4><p>邱祖殿内供奉丘处机祖师的塑像，丘处机的遗蜕（遗体）就葬在塑像下的&quot;邱祖处顺堂&quot;内。</p><h3 id="四御殿" tabindex="-1">四御殿 <a class="header-anchor" href="#四御殿" aria-label="Permalink to &quot;四御殿&quot;">​</a></h3><p>四御殿供奉道教四御（四位辅佐玉皇大帝的神仙）。</p><h2 id="白云观三宝" tabindex="-1">白云观三宝 <a class="header-anchor" href="#白云观三宝" aria-label="Permalink to &quot;白云观三宝&quot;">​</a></h2><p>白云观有&quot;三宝&quot;，是镇观之宝：</p><h3 id="第一宝-明版《道藏》" tabindex="-1">第一宝：明版《道藏》 <a class="header-anchor" href="#第一宝-明版《道藏》" aria-label="Permalink to &quot;第一宝：明版《道藏》&quot;">​</a></h3><p>白云观藏有明代正统年间刊刻的《道藏》，是道教经典的总汇，极为珍贵。</p><h3 id="第二宝-唐石雕老子像" tabindex="-1">第二宝：唐石雕老子像 <a class="header-anchor" href="#第二宝-唐石雕老子像" aria-label="Permalink to &quot;第二宝：唐石雕老子像&quot;">​</a></h3><p>白云观藏有唐代石雕老子像，是唐代石刻艺术的精品。</p><h3 id="第三宝-元代石刻-长春真人玄风庆会图" tabindex="-1">第三宝：元代石刻&quot;长春真人玄风庆会图&quot; <a class="header-anchor" href="#第三宝-元代石刻-长春真人玄风庆会图" aria-label="Permalink to &quot;第三宝：元代石刻&quot;长春真人玄风庆会图&quot;&quot;">​</a></h3><p>这是记述丘处机西行见成吉思汗的石刻，是研究元代历史的重要资料。</p><h2 id="摸石猴" tabindex="-1">摸石猴 <a class="header-anchor" href="#摸石猴" aria-label="Permalink to &quot;摸石猴&quot;">​</a></h2><p>白云观有&quot;摸石猴&quot;的习俗，是民间祈福的传统。</p><h3 id="三只石猴" tabindex="-1">三只石猴 <a class="header-anchor" href="#三只石猴" aria-label="Permalink to &quot;三只石猴&quot;">​</a></h3><p>白云观山门外的墙壁上刻有三只石猴，分别位于不同的地方：</p><ul><li><strong>第一只</strong>：在山门右侧墙壁上</li><li><strong>第二只</strong>：在山门内影壁上</li><li><strong>第三只</strong>：在东院雷祖殿墙上</li></ul><h3 id="摸猴祈福" tabindex="-1">摸猴祈福 <a class="header-anchor" href="#摸猴祈福" aria-label="Permalink to &quot;摸猴祈福&quot;">​</a></h3><p>民间传说，摸石猴可以祛病消灾、祈福纳祥。每年春节，都有大量香客来白云观摸石猴。</p><h3 id="铁打白云观" tabindex="-1">&quot;铁打白云观&quot; <a class="header-anchor" href="#铁打白云观" aria-label="Permalink to &quot;&quot;铁打白云观&quot;&quot;">​</a></h3><p>白云观建筑坚固，历经数百年风雨依然完好，民间有&quot;铁打白云观&quot;之说。</p><h2 id="白云观庙会" tabindex="-1">白云观庙会 <a class="header-anchor" href="#白云观庙会" aria-label="Permalink to &quot;白云观庙会&quot;">​</a></h2><p>白云观庙会是北京著名的传统庙会，每年春节期间举行。</p><h3 id="庙会时间" tabindex="-1">庙会时间 <a class="header-anchor" href="#庙会时间" aria-label="Permalink to &quot;庙会时间&quot;">​</a></h3><p>每年农历正月初一至十九，以正月初八、初九、十九最盛。</p><h3 id="庙会内容" tabindex="-1">庙会内容 <a class="header-anchor" href="#庙会内容" aria-label="Permalink to &quot;庙会内容&quot;">​</a></h3><ul><li><strong>祈福法会</strong>：道教祈福仪式</li><li><strong>民俗表演</strong>：舞狮、高跷等</li><li><strong>小吃摊位</strong>：传统小吃</li><li><strong>摸石猴</strong>：摸石猴祈福</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约1-2小时）</strong>：</p><p>山门（摸第一只石猴） → 窝风桥 → 灵官殿 → 玉皇殿 → 老律堂 → 邱祖殿 → 四御殿 → 摸第三只石猴 → 出观</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线/9号线军事博物馆站C口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">3路、9路、40路等白云观站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从北京西站步行约20分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>摸石猴</strong>：找到三只石猴，摸摸祈福</li><li><strong>春节庙会</strong>：春节庙会人极多，建议错峰</li><li><strong>道教礼仪</strong>：进入殿内保持安静</li><li><strong>请香</strong>：门口可请香</li><li><strong>周边游览</strong>：可与中国军事博物馆一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">军事博物馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">国家级军事博物馆</td></tr><tr><td style="text-align:left;">北京西站</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">火车站</td></tr><tr><td style="text-align:left;">中华世纪坛</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">文化建筑</td></tr><tr><td style="text-align:left;">玉渊潭公园</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">樱花名园</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>白云观是全国重点文物保护单位，是中国道教协会的所在地。</p><p>白云观是道教全真龙门派祖庭，在全真教中地位崇高。丘处机祖师在此修道并葬于此，使白云观成为全真教的圣地。</p><p>白云观保存了大量道教文物，是研究道教文化的重要场所。</p><hr><p><strong>📍 地址</strong>：北京市西城区白云观街9号 <strong>📞 电话</strong>：010-63463531</p>',71)])])}const g=a(o,[["render",i]]);export{b as __pageData,g as default};
